# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
from mysql.connector import Error
import os

def create_connection(host, database, user, password):
    connection = None
    try:
        connection = mysql.connector.connect(
            host=host,
            database=database,
            user=user,
            password=password,
            allow_local_infile=True
        )
        print("Successfully connected to MySQL database")
    except Error as e:
        print(f"Error connecting to MySQL: {e}")
    return connection

def execute_load_data_infile(connection, file_path, table_name, fields_terminated_by=',', 
                             lines_terminated_by='\n', ignore_lines=1, columns=None):
    try:
        if not os.path.exists(file_path):
            print(f"Error: File {file_path} does not exist")
            return False
        
        cursor = connection.cursor()
        
        cursor.execute("SET GLOBAL local_infile = 1")
        
        columns_clause = ""
        if columns:
            columns_clause = f" ({', '.join(columns)})"
        
        query = "LOAD DATA LOCAL INFILE '{}' INTO TABLE {} FIELDS TERMINATED BY '{}' LINES TERMINATED BY '{}' IGNORE {} LINES{}".format(
            file_path.replace('\\', '/'),
            table_name,
            fields_terminated_by,
            lines_terminated_by,
            ignore_lines,
            columns_clause
        )
        
        print(f"Executing query: {query}")
        cursor.execute(query)
        connection.commit()
        
        print(f"Successfully loaded data from {file_path} into table {table_name}")
        print(f"Rows affected: {cursor.rowcount}")
        
        cursor.close()
        return True
        
    except Error as e:
        print(f"Error executing LOAD DATA INFILE: {e}")
        connection.rollback()
        return False

def bulk_import_multiple_files(connection, import_config_list):
    for config in import_config_list:
        file_path = config.get('file_path')
        table_name = config.get('table_name')
        fields_terminated_by = config.get('fields_terminated_by', ',')
        lines_terminated_by = config.get('lines_terminated_by', '\n')
        ignore_lines = config.get('ignore_lines', 1)
        columns = config.get('columns', None)
        
        print(f"\n{'='*60}")
        print(f"Processing file: {file_path}")
        print(f"Target table: {table_name}")
        
        execute_load_data_infile(
            connection, 
            file_path, 
            table_name, 
            fields_terminated_by,
            lines_terminated_by,
            ignore_lines,
            columns
        )

def interactive_import(connection):
    while True:
        print("\n" + "="*60)
        print("MySQL Bulk Data Import Tool")
        print("="*60)
        
        file_path = input("Enter the file path (or 'quit' to exit): ").strip()
        
        if file_path.lower() == 'quit':
            break
        
        table_name = input("Enter the target table name: ").strip()
        
        fields_terminated_by = input("Enter field delimiter (default: ','): ").strip()
        if not fields_terminated_by:
            fields_terminated_by = ','
        
        lines_terminated_by = input("Enter line terminator (default: '\\n'): ").strip()
        if not lines_terminated_by:
            lines_terminated_by = '\n'
        elif lines_terminated_by == '\\r\\n':
            lines_terminated_by = '\r\n'
        elif lines_terminated_by == '\\n':
            lines_terminated_by = '\n'
        
        ignore_lines = input("Enter number of lines to ignore (default: 1): ").strip()
        ignore_lines = int(ignore_lines) if ignore_lines else 1
        
        columns_input = input("Enter column names (comma-separated, or press Enter to skip): ").strip()
        columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
        
        execute_load_data_infile(
            connection,
            file_path,
            table_name,
            fields_terminated_by,
            lines_terminated_by,
            ignore_lines,
            columns
        )
        
        continue_import = input("\nDo you want to import another file? (yes/no): ").strip().lower()
        if continue_import != 'yes':
            break

def main():
    host = input("Enter MySQL host (default: localhost): ").strip() or "localhost"
    database = input("Enter database name: ").strip()
    user = input("Enter MySQL username: ").strip()
    password = input("Enter MySQL password: ").strip()
    
    connection = create_connection(host, database, user, password)
    
    if connection and connection.is_connected():
        print("\nChoose import mode:")
        print("1. Interactive mode (enter file details one by one)")
        print("2. Batch mode (configure multiple imports)")
        
        mode = input("Enter choice (1 or 2): ").strip()
        
        if mode == '1':
            interactive_import(connection)
        elif mode == '2':
            import_configs = []
            
            while True:
                file_path = input("\nEnter file path: ").strip()
                table_name = input("Enter table name: ").strip()
                
                fields_terminated_by = input("Enter field delimiter (default: ','): ").strip() or ','
                lines_terminated_by = input("Enter line terminator (default: '\\n'): ").strip() or '\n'
                if lines_terminated_by == '\\r\\n':
                    lines_terminated_by = '\r\n'
                elif lines_terminated_by == '\\n':
                    lines_terminated_by = '\n'
                    
                ignore_lines = input("Enter number of lines to ignore (default: 1): ").strip()
                ignore_lines = int(ignore_lines) if ignore_lines else 1
                
                columns_input = input("Enter column names (comma-separated, or press Enter to skip): ").strip()
                columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
                
                import_configs.append({
                    'file_path': file_path,
                    'table_name': table_name,
                    'fields_terminated_by': fields_terminated_by,
                    'lines_terminated_by': lines_terminated_by,
                    'ignore_lines': ignore_lines,
                    'columns': columns
                })
                
                add_more = input("\nAdd another file? (yes/no): ").strip().lower()
                if add_more != 'yes':
                    break
            
            bulk_import_multiple_files(connection, import_configs)
        
        connection.close()
        print("\nConnection closed. Import process completed.")
    else:
        print("Failed to connect to database")

if __name__ == "__main__":
    main()